
(() => {
  function ready(fn){ if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', fn); else fn(); }
  function classify(text, href, bodyClass){ const low = `${text} ${href}`.toLowerCase(); if (bodyClass.includes('guide-casino')) { if (/손절|수익잠금|stop/.test(low)) return '세션관리'; if (/켈리|비율|proportional/.test(low)) return '비율형'; if (/파롤리|reverse|one-three|오스카/.test(low)) return '연승형'; if (/정액|flat|half kelly|하프 켈리/.test(low)) return '안정형'; return '진행형'; } if (bodyClass.includes('guide-minigame')) { if (/커뮤니티/.test(low)) return '커뮤니티'; if (/라인|엔트리|네임드|로투스|eos|pbg/.test(low) || /\/entry\/|\/named\/|\/lotus\/|\/eos\/|\/pbg\//.test(href)) return '라인명'; return '게임계열'; } return href.includes('/casino-betting/') ? '카지노' : href.includes('/minigame/') ? '미니게임' : '전체'; }
  function setupHub(){ if (!document.body.classList.contains('guide-hub') || document.querySelector('.guide-filter')) return; const bodyClass = document.body.className || ''; const hostSection = document.querySelector('#library') || document.querySelector('main .section'); if (!hostSection) return; const cards = Array.from(hostSection.querySelectorAll('a.link-card, a.strategy-card, .grid.grid-3 > a')); if (!cards.length) return; const wrap = document.createElement('div'); wrap.className = 'guide-filter'; const types = ['전체', ...Array.from(new Set(cards.map((card) => classify(card.textContent || '', card.getAttribute('href') || '', bodyClass))))]; wrap.innerHTML = '<div class="guide-filter__head"><div><strong>빠른 탐색</strong><span>기법·게임 성격별로 먼저 좁힌 뒤, 카드 설명을 짧게 훑고 들어가면 훨씬 빠르게 고를 수 있습니다.</span></div><div class="guide-filter__status">총 '+cards.length+'개 항목</div></div><div class="guide-filter__search"><input type="search" placeholder="기법명, 게임명, 라인명 검색" aria-label="가이드 검색"></div><div class="guide-filter__chips"></div>'; hostSection.querySelector('.container')?.prepend(wrap); const chipHost = wrap.querySelector('.guide-filter__chips'); const search = wrap.querySelector('input'); const status = wrap.querySelector('.guide-filter__status'); let activeType = '전체'; types.forEach((type, index) => { const btn = document.createElement('button'); btn.type='button'; btn.textContent=type; if(index===0) btn.className='is-active'; btn.addEventListener('click',()=>{ activeType=type; chipHost.querySelectorAll('button').forEach((el)=>el.classList.toggle('is-active', el===btn)); render();}); chipHost.appendChild(btn); }); let empty = null; function render(){ const q=(search.value||'').trim().toLowerCase(); let visible=0; cards.forEach((card)=>{ const text=(card.textContent||'').toLowerCase(); const href=(card.getAttribute('href')||'').toLowerCase(); const type=classify(text, href, bodyClass); const pass=(activeType==='전체'||type===activeType)&&(!q||text.includes(q)||href.includes(q)); card.style.display=pass?'':'none'; if(pass) visible++; }); status.textContent=`${activeType} · ${visible}개 표시`; if(!empty){ empty=document.createElement('div'); empty.className='guide-empty'; empty.textContent='조건에 맞는 항목이 없습니다. 다른 키워드나 분류로 다시 확인해 주세요.'; } if(visible===0){ if(!empty.isConnected) hostSection.querySelector('.container')?.appendChild(empty); } else if(empty.isConnected){ empty.remove(); } } search.addEventListener('input', render); render(); }
  function setupDetail(){ if (!document.body.classList.contains('guide-detail')) return; const heroMain=document.querySelector('.hero-main'); if(!heroMain) return; if(!heroMain.querySelector('.guide-topline')){ const items=Array.from(heroMain.querySelectorAll('.summary-item b, .summary-item span')).slice(0,6).map((el)=>(el.textContent||'').trim()).filter(Boolean); if(items.length){ const topline=document.createElement('div'); topline.className='guide-topline'; topline.innerHTML=items.slice(0,4).map((t)=>`<span>${t}</span>`).join(''); const summary=heroMain.querySelector('.summary-grid'); (summary||heroMain).insertAdjacentElement('afterend', topline); } } const article=document.querySelector('.panel.article'); if(article && !article.querySelector('.guide-ops-callout')){ const concept=article.querySelector('#profit p, #tips ul, #rule p'); if(concept){ const box=document.createElement('div'); box.className='guide-ops-callout'; box.innerHTML='<b>실전 읽는 기준</b><p>이 페이지는 결과를 보장하는 설명이 아니라, 어떤 구간에서 손익과 리스크가 갈리는지 빠르게 파악하도록 돕는 운영 참고용 구조입니다. 먼저 구조를 읽고, 다음으로 종료 기준과 금지 실수를 함께 확인하는 순서가 가장 좋습니다.</p>'; article.prepend(box); } } const jump=document.querySelector('.article-jump'); if(jump && !article.querySelector('.guide-mini-nav')){ const nav=document.createElement('div'); nav.className='guide-mini-nav'; nav.innerHTML=Array.from(jump.querySelectorAll('a')).slice(0,6).map((a)=>`<a href="${a.getAttribute('href')}">${a.textContent.trim()}</a>`).join(''); jump.insertAdjacentElement('afterend', nav); } document.querySelectorAll('.link-card .btn.btn-ghost.btn-sm').forEach((btn)=>{ if((btn.textContent||'').includes('페이지 보기')) btn.textContent='자세히 보기'; }); }
  ready(() => { setupHub(); setupDetail(); });
})();
